  ('locality-1fb53453-moex-00080', 'locality-1fb53453', 'locality-1fb53453-moex-113-3082b5f1', 'sub-locality-1fb53453-02', NULL, 'single_choice', '關於訴願機關審查範圍之敘述，下列何者正確？', '["訴願機關原則上僅得審查行政處分之合法性", "訴願機關審查大學對大學生所為與講學有關之行政處分，應適度尊重大學之專業判斷", "訴願機關得就地方自治團體辦理自治事項所為行政處分之合目的性進行審查", "訴願機關得以自己之判斷取代考試評分事件中原處分機關之判斷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:33+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "317", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('locality-1fb53453-moex-00081', 'locality-1fb53453', 'locality-1fb53453-moex-113-3082b5f1', 'sub-locality-1fb53453-02', NULL, 'single_choice', '關於訴願管轄之敘述，下列何者正確？', '["不服公平交易委員會之行政處分者，應以行政院為訴願管轄機關", "汽車燃料使用費之徵收，應以交通部為訴願管轄機關", "同一直轄市主管之數個高級中學成立聯合甄審委員會，對於教師新聘事項進行評審，以教育部 為訴願管轄機關", "有關國民年金保險事項所為之核定，以勞動部勞工保險局為訴願管轄機關"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:33+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "317", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('locality-1fb53453-moex-00082', 'locality-1fb53453', 'locality-1fb53453-moex-113-3082b5f1', 'sub-locality-1fb53453-02', NULL, 'single_choice', '依最新司法實務見解，A大學對所屬教師不予續聘決定，教師不服而提起申訴，經申訴評議決定 駁回後，教師復向教育部中央教師申訴評議委員會提起再申訴，再申訴決定撤銷大學不予續聘決 定，A大學得否就再申訴決定提起行政訴訟？', '["無論公立或私立大學均不得提起行政訴訟", "無論公立或私立大學均得提起行政訴訟", "若該大學係屬公立大學，則不得提起行政訴訟；若屬私立大學，則得提起行政訴訟", "若該大學係屬私立大學，則不得提起行政訴訟；若屬公立大學，則得提起行政訴訟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:33+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "317", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('locality-1fb53453-moex-00083', 'locality-1fb53453', 'locality-1fb53453-moex-113-3082b5f1', 'sub-locality-1fb53453-02', NULL, 'single_choice', '甲原經乙市政府社會局核定為低收入戶並按月領有低收入生活扶助，嗣後社會局查知甲已將戶籍 遷出乙市，乃以A函通知甲自即日起廢止其低收入戶資格並停止發給生活扶助。甲不服，循序提 起訴願及撤銷訴訟，經行政法院撤銷A函，但社會局僅繼續發給確定判決後之生活扶助。甲依法 應如何救濟？', '["提起再審", "提起課予義務訴訟", "請求行政訴訟強制執行", "提起一般給付訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:33+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "317", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('locality-1fb53453-moex-00084', 'locality-1fb53453', 'locality-1fb53453-moex-113-3082b5f1', 'sub-locality-1fb53453-02', NULL, 'single_choice', '關於行政裁量之敘述，下列何者錯誤？', '["法院在認定裁量怠惰時，應視該被指摘漏未考量之因素在個案中之權重，而為決定", "行政機關為裁量時，若違反平等原則，即構成裁量瑕疵", "行政機關以狀態責任人為裁罰對象時，應斟酌其有無事實支配管領力、能否有效為停止使用等 情事", "行政機關於個案行使裁量權時，作成不同於裁量基準之決定，即構成裁量濫用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:33+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "317", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('locality-1fb53453-moex-00085', 'locality-1fb53453', 'locality-1fb53453-moex-113-3082b5f1', 'sub-locality-1fb53453-02', NULL, 'single_choice', '有關國家賠償責任之敘述，下列何者錯誤？', '["外國人在一定條件下亦得請求國家賠償", "受委託行使公權力之私人屬於國家賠償法上之公務員概念", "僅行政處分才屬於行使公權力之概念", "公務員事實認定錯誤亦屬違法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:33+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "317", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('locality-1fb53453-moex-00086', 'locality-1fb53453', 'locality-1fb53453-moex-112-0b2477b6', 'sub-locality-1fb53453-03', NULL, 'essay', '人類的情緒包含著認知評估、生理反應、表情反應、行為衝動及主觀經
