（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:33+00:00", "source_pdf_sha1": "e290db51bac3", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "318", "s": "1401", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "心理學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('locality-1fb53453-moex-00087', 'locality-1fb53453', 'locality-1fb53453-moex-112-0b2477b6', 'sub-locality-1fb53453-03', NULL, 'essay', '一個人往往會推論他人或自己行為背後的原因，這就是所謂的歸因
